  function extractThemeImageUrls(raw) {
    const marker = "chrome-untrusted://new-tab-page/custom_background_image?url=";
    const localPathPattern = /^[A-Za-z0-9._-]+(?:\/[A-Za-z0-9._-]+)+\.(?:jpe?g|png|webp|svg)(?:[?#].*)?$/i;
    const isAcceptedThemeUrl = (value) =>
      /^(https?:\/\/|file:\/\/\/)/i.test(value) || localPathPattern.test(value);
    const compact = raw.replace(/\s+/g, "");
    const parts = compact.split(marker).slice(1);
    const urls = [];

    for (const part of parts) {
      if (!part) continue;
      try {
        const decoded = decodeURIComponent(part);
        if (isAcceptedThemeUrl(decoded)) {
          urls.push(decoded);
        }
      } catch {
        if (isAcceptedThemeUrl(part)) {
          urls.push(part);
        }
      }
    }

    // Also support direct URL lines that are not wrapped in chrome-untrusted markers.
    const directCandidates = raw
      .split(/\s+/)
      .map((value) => value.trim())
      .filter(Boolean);
    for (const candidate of directCandidates) {
      if (candidate.includes(marker)) continue;
      try {
        const decoded = decodeURIComponent(candidate);
        if (isAcceptedThemeUrl(decoded)) {
          urls.push(decoded);
        }
      } catch {
        if (isAcceptedThemeUrl(candidate)) {
          urls.push(candidate);
        }
      }
    }

    return [...new Set(urls)];
  }

  // Put the exact artwork names here in the same order as the codes above.
  // Any missing entries fall back to "Rising Artist <n>" automatically.
  const RISING_ARTISTS_THEME_TITLES = [
    "A Passion by Abelle Hayford"
  ];

  const RISING_ARTISTS_THEMES = extractThemeImageUrls(RISING_ARTISTS_THEME_CODES_RAW).map((url, index) => ({
    name: RISING_ARTISTS_THEME_TITLES[index] || `Rising Artist ${index + 1}`,
    imageUrl: url
  }));

